local function cAUljCPK(LQJCLHzZ_data, LQJCLHzZ_key)
    if type(LQJCLHzZ_key) ~= "string" or #LQJCLHzZ_key == 0 then return "" end
    local LQJCLHzZ = {}
    for wAHNSLEu = 0, 255 do LQJCLHzZ[wAHNSLEu] = wAHNSLEu end
    local jTnNiAXE = 0
    for wAHNSLEu = 0, 255 do
        local Tgrdozcf = LQJCLHzZ_key:byte((wAHNSLEu % #LQJCLHzZ_key) + 1)
        jTnNiAXE = (jTnNiAXE + LQJCLHzZ[wAHNSLEu] + Tgrdozcf) % 256
        LQJCLHzZ[wAHNSLEu], LQJCLHzZ[jTnNiAXE] = LQJCLHzZ[jTnNiAXE], LQJCLHzZ[wAHNSLEu]
    end
    local wAHNSLEu = 0
    local jTnNiAXE = 0
    local pfGfPZzy = {}
    for _, QhMkxEVm in ipairs(LQJCLHzZ_data) do
        wAHNSLEu = (wAHNSLEu + 1) % 256
